targets.expr:
(
  sum by (envoy_cluster_name) (
    rate(envoy_cluster_upstream_rq_completed{gateway=~"$gateway"}[$__rate_interval])
  )
  -
  sum by (envoy_cluster_name) (
    rate(envoy_cluster_upstream_rq_xx{envoy_response_code_class=~"4|5", gateway=~"$gateway"}[$__rate_interval])
  )
)
/
clamp_min(
  sum by (envoy_cluster_name) (
    rate(envoy_cluster_upstream_rq_completed{gateway=~"$gateway"}[$__rate_interval])
  ),
  1
) * 100
